  double Delta_x = Delta;

  double Delta_y = Delta;





  double x = ((ig + 1)/2. + (point.i - 2))*Delta + X0; NOT_UNUSED(x);

  double y = ((jg + 1)/2. + (point.j - 2))*Delta + Y0;



  NOT_UNUSED(y);



  double z = 0.;

  NOT_UNUSED(z);

