static int balanced_pid (long index, long nt, int nproc)
{
  long ne = ( 1 > (nt/nproc) ? 1 : (nt/nproc)), nr = nt % nproc;
  int pid = index < nr*(ne + 1) ?
    index/(ne + 1) :
    nr + (index - nr*(ne + 1))/ne;
  return ( (nproc - 1) < pid ? (nproc - 1) : pid);
}


     
