static void remap_neumann (double s_r,
                           double f,
                           double df_b,
                           double C[3])
{
  C[1] = df_b;
  C[2] = 3.*(s_r - df_b/2. - f)/2.;
  C[0] = s_r - df_b - C[2];
}

static void remap_robin (double s_r,
                         double f,
                         double f_b, double lambda_b,
                         double C[3])
{
  double a = - lambda_b, s = - a + (a - 1.)/3. + 1/2.;
  double M[3][3] = {
    { - a, 1./6., a/3. },
    { 1., - 2./3., - 1./3. },
    { a - 1., 1./2, 1/2. - a }
  };
  double B[3] = { f, f_b, s_r };
  for (int i = 0; i < 3; i++) {
    C[i] = 0.;
    for (int j = 0; j < 3; j++)
      C[i] += M[i][j]*B[j];
    C[i] /= s;
  }
}

static void right_value (int nvar, double s_right[nvar],
                         int k, int n,
                         const double x[n], double f[n-1][nvar],
                         double f_b, double lambda_b, double df_b,
                         double f_t, double lambda_t, double df_t)
{
  double xk = x[k], dx = x[k+1] - xk;
  double M[4][4];
  for (int i = (k == 0); i < (k == n - 3 ? 3 : 4); i++) {
    double zeta1 = (x[i+k-1] - xk)/dx;
    double z1n = zeta1;
    double zeta0 = (x[i+k] - xk)/dx;
    double z0n = zeta0;
    for (int j = 0; j < 4; j++, z1n *= zeta1, z0n *= zeta0)
      M[i][j] = (z0n - z1n)/(j + 1);
  }







  if (k == 0) {





    if (df_b) {
      M[0][0] = 0.;
      M[0][1] = 1.;
      M[0][2] = 0.;
      M[0][3] = 0.;
    }




    else {
      M[0][0] = 1.;
      M[0][1] = - lambda_b/dx;
      M[0][2] = 0.;
      M[0][3] = 0.;
    }
  }






  if (k == n - 3) {
    double zetab = (x[k+2] - xk)/dx;
    if (df_t) {
      M[3][0] = 0.;
      M[3][1] = 1.;
      M[3][2] = 2.*zetab;
      M[3][3] = 3.*( zetab*zetab);
    }
    else {
      M[3][0] = 1.;
      M[3][1] = zetab - lambda_t/dx;
      M[3][2] = zetab*(zetab - 2.*lambda_t/dx);
      M[3][3] = ( zetab*zetab)*(zetab - 3.*lambda_t/dx);
    }
  }

  if (!(smatrix_inverse (4, M, 1.e-30) > 1.e-20)) qassert ("/home/jacqhugo/basilisk/src/layered/remapc.h", 0, "smatrix_inverse (4, M, 1.e-30) > 1.e-20");

  for (int v = 0; v < nvar; v++) {
    double B[4];
    for (int i = (k == 0); i < (k == n - 3 ? 3 : 4); i++)
      B[i] = (x[k+i] - x[k-1+i])/dx*f[k-1+i][v];
    if (k == 0) {
      if (df_b)
        B[0] = df_b*dx;
      else
        B[0] = f_b;
    }
    if (k == n - 3) {
      if (df_t)
        B[3] = df_t*dx;
      else
        B[3] = f_t;
    }
    double c[4] = {0.,0.,0.,0.};
    for (int i = 0; i < 4; i++)
      for (int j = 0; j < 4; j++)
        c[i] += M[i][j]*B[j];
    s_right[v] = c[3];
    for (int i = 0; i < 3; i++)
      s_right[v] += c[i];
  }
}






static double minmodremap (double a, double b) {
  return a*b <= 0. ? 0. :
    fabs(a) < fabs(b) ? a : b;
}






static void remap_central (int nvar,
                           const double s_l[nvar], const double s_r[nvar],
                           const int n, const double x[n], double f[n-1][nvar],
                           const int k,
                           double C[3][nvar],
                           const bool limiter)
{
  double xk = x[k], dx = x[k+1] - xk;
  for (int v = 0; v < nvar; v++) {
    double sl = s_l[v], sr = s_r[v];




    if (limiter) {
      if ((f[k+1][v] - f[k][v])*(f[k][v] - f[k-1][v]) < 0.) {
        sl = f[k][v];
        sr = f[k][v];
      }
      else {
        double sigma_left = 2.*(f[k][v] - f[k-1][v])/dx;
        double sigma_center = 2.*(f[k+1][v] - f[k-1][v])/(x[k+2] - x[k-1] + dx);
        double sigma_right = 2.*(f[k+1][v] - f[k][v])/dx;
        double sigma = minmodremap(sigma_center, minmodremap(sigma_left, sigma_right));
        if ((sl - f[k-1][v])*(f[k][v] - sl) < 0.)
          sl = f[k][v] - 1./2.*dx*sigma;
        if ((sr - f[k][v])*(f[k+1][v] - sr) < 0.)
          sr = f[k][v] + 1./2.*dx*sigma;
      }
    }

    C[0][v] = sl;
    C[1][v] = 6.*f[k][v] - 2.*sr - 4.*sl;
    C[2][v] = 3.*(sr + sl - 2.*f[k][v]);

    if (limiter && C[1][v]*C[2][v] < 0. && C[1][v]/C[2][v] > - 2.) {
      if (C[1][v]/C[2][v] > - 1.)
        sr = 3.*f[k][v] - 2.*sl;
      else
        sl = 3.*f[k][v] - 2.*sr;




      C[0][v] = sl;
      C[1][v] = 6.*f[k][v] - 2.*sr - 4.*sl;
      C[2][v] = 3.*(sr + sl - 2.*f[k][v]);
    }
  }
}

void remap_c (int npos, int nnew,
              const double xpos[npos], const double xnew[nnew],
              const int nvar,
              double fdat[npos-1][nvar], double fnew[nnew-1][nvar],
              double f_b, double lambda_b, double df_b,
              double f_t, double lambda_t, double df_t,
              bool limiter)
{






  if (!(xnew[0] == xpos[0] && xnew[nnew-1] == xpos[npos - 1])) qassert ("/home/jacqhugo/basilisk/src/layered/remapc.h", 0, "xnew[0] == xpos[0] && xnew[nnew-1] == xpos[npos - 1]");




  double x = xnew[0], s_left[nvar], C[3][nvar];
  for (int v = 0; v < nvar; v++)
    fnew[0][v] = 0., s_left[v] = 0.;
  for (int inew = 0, k = -1; inew < nnew - 1 && x < xpos[npos - 1];) {







    if (x >= xpos[k + 1]) {





      k++;




      if (k == npos - 2) {





        if (limiter && lambda_t == 1e30f)
          for (int v = 0; v < nvar; v++) {
            C[0][v] = fdat[k][v];
            C[1][v] = 0.;
            C[2][v] = 0.;
          }





        else
          for (int v = 0; v < nvar; v++) {
            double B[3];
            if (df_t)
              remap_neumann (s_left[v], fdat[k][v], - df_t*(xpos[k+1] - xpos[k]), B);
            else
              remap_robin (s_left[v], fdat[k][v], f_t, - lambda_t/(xpos[k+1] - xpos[k]), B);






            C[0][v] = B[0] + B[1] + B[2];
            C[1][v] = - B[1] - 2.*B[2];
            C[2][v] = B[2];
          }
      }
      else {






        double s_right[nvar];
        if (limiter && lambda_b == 1e30f && k == 0)
          for (int v = 0; v < nvar; v++)
            s_right[v] = fdat[0][v];
        else if (limiter && lambda_t == 1e30f && k == npos - 3)
          for (int v = 0; v < nvar; v++)
            s_right[v] = fdat[npos - 2][v];
        else
          right_value (nvar, s_right, k, npos, xpos, fdat, f_b, lambda_b, df_b, f_t, lambda_t, df_t);




        if (k == 0)
          for (int v = 0; v < nvar; v++) {
            double B[3];
            if (df_b)
              remap_neumann (s_right[v], fdat[0][v], df_b*(xpos[1] - xpos[0]), B);
            else
              remap_robin (s_right[v], fdat[0][v], f_b, lambda_b/(xpos[1] - xpos[0]), B);
            for (int i = 0; i < 3; i++)
              C[i][v] = B[i];
          }





        else
          remap_central (nvar, s_left, s_right, npos, xpos, fdat, k, C, limiter);




        for (int v = 0; v < nvar; v++)
          s_left[v] = s_right[v];
      }
    }

    double xe;
    int jnew = inew;
    if (xnew[inew + 1] < xpos[k + 1]) {
      jnew = inew + 1;
      xe = xnew[jnew];
      for (int v = 0; v < nvar; v++)
        fnew[jnew][v] = 0.;
    }
    else
      xe = xpos[k + 1];

    double xk = xpos[k], dx = xpos[k+1] - xk, dx1 = dx/(xnew[inew + 1] - xnew[inew]);
    double a = (x - xk)/dx, b = (xe - xk)/dx;
    if (!(a >= 0. && a <= b && b <= 1.)) qassert ("/home/jacqhugo/basilisk/src/layered/remapc.h", 0, "a >= 0. && a <= b && b <= 1.");
    for (int v = 0; v < nvar; v++) {
      double an = a, bn = b;
      for (int i = 0; i < 3; i++, an *= a, bn *= b)
        fnew[inew][v] += C[i][v]/(i + 1)*(bn - an)*dx1;
    }






    x = xe;
    inew = jnew;
  }
}

